{
  "name": "HabitPulse",
  "description": "A widget-style habit tracker with AI-driven insights, monthly reviews, and crystal-clear visualization of personal growth."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Habit {
  id: string;
  name: string;
  category: string;
}

// Map of date string (YYYY-MM-DD) to array of completed habit IDs
export interface HabitLogs {
  [date: string]: string[]; 
}

export interface MonthlyStats {
  totalPossible: number;
  totalCompleted: number;
  completionRate: number;
  dailyTrend: { day: number; completed: number; total: number }[];
  habitPerformance: { id: string; name: string; count: number; rate: number }[];
}

export enum AppView {
  TRACKER = 'TRACKER',
  REVIEW = 'REVIEW',
}

export interface AIInsightResponse {
  message: string;
  tone: 'encouraging' | 'warning' | 'celebratory';
}

import { GoogleGenAI, Type } from "@google/genai";
import { MonthlyStats } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API_KEY not found in environment variables");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const getProgressInsight = async (
  stats: MonthlyStats,
  currentDate: Date
): Promise<{ message: string; tone: string }> => {
  const client = getClient();
  if (!client) {
    return { 
      message: "API Key missing. Please configure your environment.", 
      tone: "warning" 
    };
  }

  const prompt = `
    You are a personal habit coach. Analyze this user's progress for ${currentDate.toLocaleString('default', { month: 'long' })}.

    Data:
    - Completion Rate: ${stats.completionRate.toFixed(1)}%
    - Best Habit: ${stats.habitPerformance.sort((a, b) => b.rate - a.rate)[0]?.name || 'None'}
    - Worst Habit: ${stats.habitPerformance.sort((a, b) => a.rate - b.rate)[0]?.name || 'None'}
    - Trend: The user has completed ${stats.totalCompleted} tasks out of ${stats.totalPossible} opportunities so far.

    If the rate is below 50%, give a strict but helpful warning about their downward progress.
    If between 50-80%, be encouraging.
    If above 80%, be celebratory.
    Keep the message short (under 50 words) and impactful.
  `;

  try {
    const response = await client.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            message: { type: Type.STRING },
            tone: { type: Type.STRING, enum: ["warning", "encouraging", "celebratory"] }
          },
          required: ["message", "tone"]
        }
      }
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("No response from AI");

    return JSON.parse(jsonText);
  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      message: "Keep pushing! Consistency is key.",
      tone: "encouraging"
    };
  }
};

export const getEndOfMonthReview = async (
  stats: MonthlyStats,
  monthName: string
): Promise<string> => {
  const client = getClient();
  if (!client) return "Unable to generate review due to missing API configuration.";

  const missedHabits = stats.habitPerformance
    .filter(h => h.rate < 60)
    .map(h => h.name)
    .join(", ");

  const prompt = `
    Write a concise end-of-month review for ${monthName}.
    The user achieved a ${stats.completionRate.toFixed(1)}% completion rate.
    Habits they struggled with: ${missedHabits || "None!"}.
    Provide 3 specific bullet points on how to improve next month.
    Format as valid Markdown.
  `;

  try {
    const response = await client.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
    });
    return response.text || "No review generated.";
  } catch (error) {
    return "Failed to generate review.";
  }
};

import React, { useRef, useEffect } from 'react';
import { Check, X } from 'lucide-react';
import { Habit, HabitLogs } from '../types';

interface HabitGridProps {
  habits: Habit[];
  logs: HabitLogs;
  currentDate: Date;
  onToggle: (habitId: string, dateStr: string) => void;
  onAddHabit: () => void;
  onDeleteHabit: (id: string) => void;
}

export const HabitGrid: React.FC<HabitGridProps> = ({
  habits,
  logs,
  currentDate,
  onToggle,
  onAddHabit,
  onDeleteHabit
}) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  // Calculate days in the month
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const daysArray = Array.from({ length: daysInMonth }, (_, i) => i + 1);

  // Auto-scroll to today
  useEffect(() => {
    if (scrollContainerRef.current) {
      const today = new Date().getDate();
      // Simple approximation of scroll position: (Day - 5) * Column Width
      const scrollPos = Math.max 
        (0, (today - 4) * 60);
      scrollContainerRef.current.scrollLeft = scrollPos;
    }
  }, [currentDate]);

  const getDayLabel = (day: number) => {
    const date = new Date(year, month, day);
    return date.toLocaleDateString('en-US', { weekday: 'narrow' });
  };

  const isToday = (day: number) => {
    const today = new Date();
    return (
      day === today.getDate() &&
      month === today.getMonth() &&
      year === today.getFullYear()
    );
  };

  const formatDate = (day: number) => {
    return `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
  };

  return (
    <div className="flex flex-col h-full bg-surface rounded-3xl overflow-hidden shadow-2xl border border-slate-700">
      {/* Header / Controls */}
      <div className="p-6 border-b border-slate-700 flex justify-between items-center bg-slate-900/50">
        <div>
          <h2 className="text-2xl font-bold text-white">Habit Matrix</h2>
          <p className="text-slate-400 text-sm">Track your daily consistency</p>
        </div>
        <button
          onClick={onAddHabit}
          className="px-4 py-2 bg-primary hover:bg-blue-600 text-white rounded-lg transition-colors font-medium flex items-center gap-2"
        >
          <span>+ New Habit</span>
        </button>
      </div>

      {/* Grid Container */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Sticky Left Column: Habit Names */}
        <div className="w-48 flex-shrink-0 bg-surface z-20 border-r border-slate-700 shadow-xl">
          <div className="h-12 border-b border-slate-700 bg-slate-800/80 backdrop-blur sticky top-0 z-30 flex items-center px-4 font-semibold text-slate-300">
            Habit Name
          </div>
          {habits.map((habit) => (
            <div
              key={habit.id}
              className="h-14 border-b border-slate-700/50 flex items-center justify-between px-4 group hover:bg-slate-700/30 transition-colors"
            >
              <span className="truncate text-sm font-medium text-slate-200" title={habit.name}>
                {habit.name}
              </span>
              <button 
                onClick={() => onDeleteHabit(habit.id)}
                className="opacity-0 group-hover:opacity-100 text-slate-500 hover:text-danger transition-opacity"
              >
                <X size={14} />
              </button>
            </div>
          ))}
          {habits.length === 0 && (
            <div className="p-4 text-sm text-slate-500 italic">No habits added yet.</div>
          )}
        </div>

        {/* Scrollable Days Area */}
        <div 
          ref={scrollContainerRef}
          className="flex-1 overflow-x-auto overflow-y-hidden"
        >
          <div className="inline-block min-w-full">
            {/* Days Header */}
            <div className="flex">
              {daysArray.map((day) => (
                <div
                  key={day}
                  className={`w-12 h-12 flex-shrink-0 flex flex-col items-center justify-center border-b border-r border-slate-700/50 ${
                    isToday(day) ? 'bg-primary/20 text-primary' : 'bg-slate-800/50 text-slate-400'
                  }`}
                >
                  <span className="text-[10px] uppercase font-bold">{getDayLabel(day)}</span>
                  <span className={`text-sm font-semibold ${isToday(day) ? 'text-white' : ''}`}>{day}</span>
                </div>
              ))}
            </div>

            {/* Checkboxes Grid */}
            <div>
              {habits.map((habit) => (
                <div key={habit.id} className="flex">
                  {daysArray.map((day) => {
                    const dateStr = formatDate(day);
                    const isCompleted = logs[dateStr]?.includes(habit.id);
                    const today = new Date();
                    const checkDate = new Date(year, month, day);
                    const isFuture = checkDate > today;

                    return (
                      <div
                        key={`${habit.id}-${day}`}
                        className={`w-12 h-14 flex-shrink-0 flex items-center justify-center border-b border-r border-slate-700/30 ${
                          isCompleted ? 'bg-primary/5' : ''
                        }`}
                      >
                        <button
                          disabled={isFuture}
                          onClick={() => onToggle(habit.id, dateStr)}
                          className={`
                            w-6 h-6 rounded flex items-center justify-center transition-all duration-200
                            ${
                              isCompleted
                                ? 'bg-primary text-white scale-100'
                                : 'bg-slate-700 text-transparent scale-90 hover:bg-slate-600'
                            }
                            ${isFuture ? 'opacity-20 cursor-not-allowed' : 'cursor-pointer'}
                          `}
                        >
                          <Check size={14} strokeWidth={4} />
                        </button>
                      </div>
                    );
                  })}
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { 
  AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, 
  BarChart, Bar, Cell 
} from 'recharts';
import { Sparkles, TrendingUp, TrendingDown, AlertCircle } from 'lucide-react';
import { MonthlyStats } from '../types';

interface VisualizationPanelProps {
  stats: MonthlyStats;
  aiMessage: string | null;
  aiTone: string;
  loadingAI: boolean;
  onRefreshAI: () => void;
}

export const VisualizationPanel: React.FC<VisualizationPanelProps> = ({
  stats,
  aiMessage,
  aiTone,
  loadingAI,
  onRefreshAI
}) => {
  const getToneColor = () => {
    switch (aiTone) {
      case 'warning': return 'bg-orange-500/10 border-orange-500/30 text-orange-400';
      case 'celebratory': return 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400';
      default: return 'bg-blue-500/10 border-blue-500/30 text-blue-400';
    }
  };

  return (
    <div className="flex flex-col h-full gap-6">

      {/* AI Assistant Card */}
      <div className={`p-6 rounded-3xl border backdrop-blur-sm transition-all duration-500 ${getToneColor()} relative overflow-hidden group`}>
        <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
          <Sparkles size={64} />
        </div>
        <div className="flex items-center gap-3 mb-3">
          <div className="p-2 bg-white/10 rounded-lg">
            {aiTone === 'warning' ? <TrendingDown size={20} /> : <TrendingUp size={20} />}
          </div>
          <h3 className="text-lg font-bold">Habit Assistant</h3>
        </div>
        <p className="text-sm font-medium leading-relaxed min-h-[60px]">
          {loadingAI ? (
            <span className="animate-pulse">Analyzing your progress patterns...</span>
          ) : (
            aiMessage || "Start tracking to get insights!"
          )}
        </p>
        {!loadingAI && (
          <button 
            onClick={onRefreshAI} 
            className="mt-4 text-xs font-bold uppercase tracking-wider hover:underline opacity-70 hover:opacity-100"
          >
            Refresh Insight
          </button>
        )}
      </div>

      {/* Main Growth Graph */}
      <div className="bg-surface rounded-3xl border border-slate-700 p-6 flex-1 flex flex-col min-h-[250px]">
        <h3 className="text-slate-300 font-semibold mb-4 flex items-center gap-2">
          <TrendingUp size={16} className="text-primary" />
          Overall Growth
        </h3>
        <div className="flex-1 w-full h-full min-h-0">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={stats.dailyTrend}>
              <defs>
                <linearGradient id="colorCompleted" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.8}/>
                  <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <Tooltip 
                contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #334155', borderRadius: '8px' }}
                itemStyle={{ color: '#fff' }}
              />
              <Area 
                type="monotone" 
                dataKey="completed" 
                stroke="#3b82f6" 
                strokeWidth={3}
                fillOpacity={1} 
                fill="url(#colorCompleted)" 
              />
            </AreaChart>
          </ResponsiveContainer>
        </div>
        <div className="mt-2 flex justify-between text-xs text-slate-500">
          <span>Start of Month</span>
          <span>Today</span>
        </div>
      </div>

      {/* Individual Habit Performance */}
      <div className="bg-surface rounded-3xl border border-slate-700 p-6 flex-1 flex flex-col min-h-[250px]">
        <h3 className="text-slate-300 font-semibold mb-4 flex items-center gap-2">
          <AlertCircle size={16} className="text-accent" />
          Habit Consistency
        </h3>
        <div className="flex-1 w-full h-full min-h-0">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart 
              layout="vertical" 
              data={stats.habitPerformance.sort((a, b) => a.rate - b.rate).slice(0, 5)}
              margin={{ left: 20, right: 30 }}
            >
              <XAxis type="number" hide />
              <YAxis 
                type="category" 
                dataKey="name" 
                width={80} 
                tick={{ fill: '#94a3b8', fontSize: 10 }} 
                interval={0}
              />
              <Tooltip 
                cursor={{fill: '#334155', opacity: 0.4}}
                contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #334155', borderRadius: '8px' }}
                formatter={(value: number) => [`${value.toFixed(0)}%`, 'Completion']}
              />
              <Bar dataKey="rate" radius={[0, 4, 4, 0]} barSize={20}>
                {stats.habitPerformance.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.rate < 50 ? '#ef4444' : entry.rate < 80 ? '#3b82f6' : '#10b981'} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Habit, HabitLogs, MonthlyStats, AppView } from './types';
import { HabitGrid } from './components/HabitGrid';
import { VisualizationPanel } from './components/VisualizationPanel';
import { getProgressInsight, getEndOfMonthReview } from './services/geminiService';
import { ChevronLeft, ChevronRight, FileText, LayoutDashboard } from 'lucide-react';

const DEFAULT_HABITS: Habit[] = [
  { id: '1', name: 'Morning Jog', category: 'Health' },
  { id: '2', name: 'Read 30 mins', category: 'Growth' },
  { id: '3', name: 'Code Project', category: 'Career' },
  { id: '4', name: 'Meditation', category: 'Mental' },
];

function App() {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [habits, setHabits] = useState<Habit[]>(() => {
    const saved = localStorage.getItem('habits');
    return saved ? JSON.parse(saved) : DEFAULT_HABITS;
  });
  const [logs, setLogs] = useState<HabitLogs>(() => {
    const saved = localStorage.getItem('logs');
    return saved ? JSON.parse(saved) : {};
  });

  const [view, setView] = useState<AppView>(AppView.TRACKER);
  const [aiInsight, setAiInsight] = useState<{ message: string; tone: string } | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);
  const [reviewText, setReviewText] = useState<string>("");

  // Persistence
  useEffect(() => {
    localStorage.setItem('habits', JSON.stringify(habits));
    localStorage.setItem('logs', JSON.stringify(logs));
  }, [habits, logs]);

  // Statistics Calculation
  const stats: MonthlyStats = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const today = new Date().getDate();
    // Only count days up to today if looking at current month, else whole month
    const isCurrentMonth = month === new Date().getMonth() && year === new Date().getFullYear();
    const daysPassed = isCurrentMonth ? today : daysInMonth;

    let totalCompleted = 0;
    const totalPossible = habits.length * daysPassed;

    // Calculate Daily Trend
    const dailyTrend = Array.from({ length: daysInMonth }, (_, i) => {
      const day = i + 1;
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
      const completedCount = logs[dateStr]?.length || 0;
      // Only add to total if day has passed
      if (day <= daysPassed) totalCompleted += completedCount;

      return {
        day,
        completed: completedCount,
        total: habits.length
      };
    });

    // Calculate Individual Habit Performance
    const habitPerformance = habits.map(habit => {
      let count = 0;
      for (let d = 1; d <= daysPassed; d++) {
        const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
        if (logs[dateStr]?.includes(habit.id)) count++;
      }
      return {
        id: habit.id,
        name: habit.name,
        count,
        rate: totalPossible > 0 ? (count / daysPassed) * 100 : 0
      };
    });

    return {
      totalPossible,
      totalCompleted,
      completionRate: totalPossible > 0 ? (totalCompleted / totalPossible) * 100 : 0,
      dailyTrend,
      habitPerformance
    };
  }, [logs, habits, currentDate]);

  // AI Trigger
  const fetchInsight = useCallback(async () => {
    setLoadingAI(true);
    const result = await getProgressInsight(stats, currentDate);
    setAiInsight(result);
    setLoadingAI(false);
  }, [stats, currentDate]);

  // Initial AI Fetch
  useEffect(() => {
    // Debounce to avoid too many calls on initial load
    const t = setTimeout(() => {
      if (!aiInsight) fetchInsight();
    }, 1000);
    return () => clearTimeout(t);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once on mount or when manually refreshed via fetchInsight

  const handleToggleHabit = (habitId: string, dateStr: string) => {
    setLogs(prev => {
      const dayLogs = prev[dateStr] || [];
      const isCompleted = dayLogs.includes(habitId);
      const newDayLogs = isCompleted
        ? dayLogs.filter(id => id !== habitId)
        : [...dayLogs, habitId];

      return { ...prev, [dateStr]: newDayLogs };
    });
  };

  const handleAddHabit = () => {
    const name = prompt("Enter habit name:");
    if (name) {
      setHabits(prev => [...prev, { id: Date.now().toString(), name, category: 'General' }]);
    }
  };

  const handleDeleteHabit = (id: string) => {
    if (confirm("Delete this habit? History will remain.")) {
      setHabits(prev => prev.filter(h => h.id !== id));
    }
  };

  const changeMonth = (offset: number) => {
    setCurrentDate(prev => {
      const newDate = new Date(prev);
      newDate.setMonth(newDate.getMonth() + offset);
      return newDate;
    });
    setAiInsight(null); // Reset insight for new month
    setReviewText("");
  };

  const handleGenerateReview = async () => {
    setLoadingAI(true);
    const monthName = currentDate.toLocaleString('default', { month: 'long', year: 'numeric' });
    const review = await getEndOfMonthReview(stats, monthName);
    setReviewText(review);
    setLoadingAI(false);
  };

  return (
    <div className="min-h-screen bg-background text-slate-200 p-4 md:p-8 flex items-center justify-center font-sans">
      <div className="w-full max-w-[1600px] h-[90vh] flex flex-col gap-6">

        {/* Top Bar: Month Navigation & View Toggle */}
        <div className="flex justify-between items-center bg-surface p-4 rounded-2xl border border-slate-700 shadow-lg">
          <div className="flex items-center gap-4">
            <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-slate-700 rounded-lg transition-colors">
              <ChevronLeft />
            </button>
            <h1 className="text-2xl font-bold w-48 text-center">
              {currentDate.toLocaleString('default', { month: 'long', year: 'numeric' })}
            </h1>
            <button onClick={() => changeMonth(1)} className="p-2 hover:bg-slate-700 rounded-lg transition-colors">
              <ChevronRight />
            </button>
          </div>

          <div className="flex gap-2">
            <button 
              onClick={() => setView(AppView.TRACKER)}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${view === AppView.TRACKER ? 'bg-primary text-white shadow-lg shadow-blue-500/30' : 'text-slate-400 hover:text-white'}`}
            >
              <LayoutDashboard size={18} />
              Tracker
            </button>
            <button 
              onClick={() => {
                setView(AppView.REVIEW);
                if (!reviewText) handleGenerateReview();
              }}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${view === AppView.REVIEW ? 'bg-accent text-white shadow-lg shadow-violet-500/30' : 'text-slate-400 hover:text-white'}`}
            >
              <FileText size={18} />
              Monthly Review
            </button>
          </div>
        </div>

        {/* Main Content Area */}
        <div className="flex-1 flex gap-6 min-h-0">

          {view === AppView.TRACKER ? (
            <>
              {/* Left Side: 3/5 width */}
              <div className="flex-[3] min-w-0">
                <HabitGrid 
                  habits={habits}
                  logs={logs}
                  currentDate={currentDate}
                  onToggle={handleToggleHabit}
                  onAddHabit={handleAddHabit}
                  onDeleteHabit={handleDeleteHabit}
                />
              </div>

              {/* Right Side: 2/5 width */}
              <div className="flex-[2] min-w-0">
                <VisualizationPanel 
                  stats={stats}
                  aiMessage={aiInsight?.message || null}
                  aiTone={aiInsight?.tone || 'neutral'}
                  loadingAI={loadingAI}
                  onRefreshAI={fetchInsight}
                />
              </div>
            </>
          ) : (
            <div className="w-full bg-surface rounded-3xl border border-slate-700 p-8 overflow-y-auto">
              <h2 className="text-3xl font-bold mb-6 text-white flex items-center gap-3">
                <Sparkles className="text-accent" />
                AI Monthly Review
              </h2>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-sm mb-1">Completion Rate</div>
                  <div className="text-4xl font-bold text-primary">{stats.completionRate.toFixed(1)}%</div>
                </div>
                <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-sm mb-1">Top Performer</div>
                  <div className="text-2xl font-bold text-success truncate">
                    {stats.habitPerformance.sort((a,b) => b.rate - a.rate)[0]?.name || '-'}
                  </div>
                </div>
                <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-sm mb-1">Needs Focus</div>
                  <div className="text-2xl font-bold text-danger truncate">
                    {stats.habitPerformance.sort((a,b) => a.rate - b.rate)[0]?.name || '-'}
                  </div>
                </div>
              </div>

              <div className="bg-slate-900/50 p-8 rounded-2xl border border-slate-700">
                {loadingAI ? (
                   <div className="flex items-center gap-3 text-slate-400">
                     <div className="animate-spin h-5 w-5 border-2 border-primary border-t-transparent rounded-full"></div>
                     Generating review...
                   </div>
                ) : (
                  <article className="prose prose-invert max-w-none">
                     <pre className="whitespace-pre-wrap font-sans text-slate-300 text-lg leading-relaxed">{reviewText}</pre>
                  </article>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default App;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Habit, HabitLogs, MonthlyStats, AppView } from './types';
import { HabitGrid } from './components/HabitGrid';
import { VisualizationPanel } from './components/VisualizationPanel';
import { getProgressInsight, getEndOfMonthReview } from './services/geminiService';
import { ChevronLeft, ChevronRight, FileText, LayoutDashboard, Sparkles } from 'lucide-react';

const DEFAULT_HABITS: Habit[] = [
  { id: '1', name: 'Morning Jog', category: 'Health' },
  { id: '2', name: 'Read 30 mins', category: 'Growth' },
  { id: '3', name: 'Code Project', category: 'Career' },
  { id: '4', name: 'Meditation', category: 'Mental' },
];

function App() {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [habits, setHabits] = useState<Habit[]>(() => {
    const saved = localStorage.getItem('habits');
    return saved ? JSON.parse(saved) : DEFAULT_HABITS;
  });
  const [logs, setLogs] = useState<HabitLogs>(() => {
    const saved = localStorage.getItem('logs');
    return saved ? JSON.parse(saved) : {};
  });

  const [view, setView] = useState<AppView>(AppView.TRACKER);
  const [aiInsight, setAiInsight] = useState<{ message: string; tone: string } | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);
  const [reviewText, setReviewText] = useState<string>("");

  // Persistence
  useEffect(() => {
    localStorage.setItem('habits', JSON.stringify(habits));
    localStorage.setItem('logs', JSON.stringify(logs));
  }, [habits, logs]);

  // Statistics Calculation
  const stats: MonthlyStats = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const today = new Date().getDate();
    // Only count days up to today if looking at current month, else whole month
    const isCurrentMonth = month === new Date().getMonth() && year === new Date().getFullYear();
    const daysPassed = isCurrentMonth ? today : daysInMonth;

    let totalCompleted = 0;
    const totalPossible = habits.length * daysPassed;

    // Calculate Daily Trend
    const dailyTrend = Array.from({ length: daysInMonth }, (_, i) => {
      const day = i + 1;
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
      const completedCount = logs[dateStr]?.length || 0;
      // Only add to total if day has passed
      if (day <= daysPassed) totalCompleted += completedCount;

      return {
        day,
        completed: completedCount,
        total: habits.length
      };
    });

    // Calculate Individual Habit Performance
    const habitPerformance = habits.map(habit => {
      let count = 0;
      for (let d = 1; d <= daysPassed; d++) {
        const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
        if (logs[dateStr]?.includes(habit.id)) count++;
      }
      return {
        id: habit.id,
        name: habit.name,
        count,
        rate: totalPossible > 0 ? (count / daysPassed) * 100 : 0
      };
    });

    return {
      totalPossible,
      totalCompleted,
      completionRate: totalPossible > 0 ? (totalCompleted / totalPossible) * 100 : 0,
      dailyTrend,
      habitPerformance
    };
  }, [logs, habits, currentDate]);

  // AI Trigger
  const fetchInsight = useCallback(async () => {
    setLoadingAI(true);
    const result = await getProgressInsight(stats, currentDate);
    setAiInsight(result);
    setLoadingAI(false);
  }, [stats, currentDate]);

  // Initial AI Fetch
  useEffect(() => {
    // Debounce to avoid too many calls on initial load
    const t = setTimeout(() => {
      if (!aiInsight) fetchInsight();
    }, 1000);
    return () => clearTimeout(t);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once on mount or when manually refreshed via fetchInsight

  const handleToggleHabit = (habitId: string, dateStr: string) => {
    setLogs(prev => {
      const dayLogs = prev[dateStr] || [];
      const isCompleted = dayLogs.includes(habitId);
      const newDayLogs = isCompleted
        ? dayLogs.filter(id => id !== habitId)
        : [...dayLogs, habitId];

      return { ...prev, [dateStr]: newDayLogs };
    });
  };

  const handleAddHabit = () => {
    const name = prompt("Enter habit name:");
    if (name) {
      setHabits(prev => [...prev, { id: Date.now().toString(), name, category: 'General' }]);
    }
  };

  const handleDeleteHabit = (id: string) => {
    if (confirm("Delete this habit? History will remain.")) {
      setHabits(prev => prev.filter(h => h.id !== id));
    }
  };

  const changeMonth = (offset: number) => {
    setCurrentDate(prev => {
      const newDate = new Date(prev);
      newDate.setMonth(newDate.getMonth() + offset);
      return newDate;
    });
    setAiInsight(null); // Reset insight for new month
    setReviewText("");
  };

  const handleGenerateReview = async () => {
    setLoadingAI(true);
    const monthName = currentDate.toLocaleString('default', { month: 'long', year: 'numeric' });
    const review = await getEndOfMonthReview(stats, monthName);
    setReviewText(review);
    setLoadingAI(false);
  };

  return (
    <div className="min-h-screen bg-background text-slate-200 p-4 md:p-8 flex items-center justify-center font-sans">
      <div className="w-full max-w-[1600px] h-[90vh] flex flex-col gap-6">

        {/* Top Bar: Month Navigation & View Toggle */}
        <div className="flex justify-between items-center bg-surface p-4 rounded-2xl border border-slate-700 shadow-lg">
          <div className="flex items-center gap-4">
            <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-slate-700 rounded-lg transition-colors">
              <ChevronLeft />
            </button>
            <h1 className="text-2xl font-bold w-48 text-center">
              {currentDate.toLocaleString('default', { month: 'long', year: 'numeric' })}
            </h1>
            <button onClick={() => changeMonth(1)} className="p-2 hover:bg-slate-700 rounded-lg transition-colors">
              <ChevronRight />
            </button>
          </div>

          <div className="flex gap-2">
            <button 
              onClick={() => setView(AppView.TRACKER)}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${view === AppView.TRACKER ? 'bg-primary text-white shadow-lg shadow-blue-500/30' : 'text-slate-400 hover:text-white'}`}
            >
              <LayoutDashboard size={18} />
              Tracker
            </button>
            <button 
              onClick={() => {
                setView(AppView.REVIEW);
                if (!reviewText) handleGenerateReview();
              }}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${view === AppView.REVIEW ? 'bg-accent text-white shadow-lg shadow-violet-500/30' : 'text-slate-400 hover:text-white'}`}
            >
              <FileText size={18} />
              Monthly Review
            </button>
          </div>
        </div>

        {/* Main Content Area */}
        <div className="flex-1 flex gap-6 min-h-0">

          {view === AppView.TRACKER ? (
            <>
              {/* Left Side: 3/5 width */}
              <div className="flex-[3] min-w-0">
                <HabitGrid 
                  habits={habits}
                  logs={logs}
                  currentDate={currentDate}
                  onToggle={handleToggleHabit}
                  onAddHabit={handleAddHabit}
                  onDeleteHabit={handleDeleteHabit}
                />
              </div>

              {/* Right Side: 2/5 width */}
              <div className="flex-[2] min-w-0">
                <VisualizationPanel 
                  stats={stats}
                  aiMessage={aiInsight?.message || null}
                  aiTone={aiInsight?.tone || 'neutral'}
                  loadingAI={loadingAI}
                  onRefreshAI={fetchInsight}
                />
              </div>
            </>
          ) : (
            <div className="w-full bg-surface rounded-3xl border border-slate-700 p-8 overflow-y-auto">
              <h2 className="text-3xl font-bold mb-6 text-white flex items-center gap-3">
                <Sparkles className="text-accent" />
                AI Monthly Review
              </h2>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-sm mb-1">Completion Rate</div>
                  <div className="text-4xl font-bold text-primary">{stats.completionRate.toFixed(1)}%</div>
                </div>
                <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-sm mb-1">Top Performer</div>
                  <div className="text-2xl font-bold text-success truncate">
                    {stats.habitPerformance.sort((a,b) => b.rate - a.rate)[0]?.name || '-'}
                  </div>
                </div>
                <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-sm mb-1">Needs Focus</div>
                  <div className="text-2xl font-bold text-danger truncate">
                    {stats.habitPerformance.sort((a,b) => a.rate - b.rate)[0]?.name || '-'}
                  </div>
                </div>
              </div>

              <div className="bg-slate-900/50 p-8 rounded-2xl border border-slate-700">
                {loadingAI ? (
                   <div className="flex items-center gap-3 text-slate-400">
                     <div className="animate-spin h-5 w-5 border-2 border-primary border-t-transparent rounded-full"></div>
                     Generating review...
                   </div>
                ) : (
                  <article className="prose prose-invert max-w-none">
                     <pre className="whitespace-pre-wrap font-sans text-slate-300 text-lg leading-relaxed">{reviewText}</pre>
                  </article>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default App;

import React, { useMemo } from 'react';
import { 
  Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis,
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Legend
} from 'recharts';
import { Sparkles, Activity, PieChart as PieIcon } from 'lucide-react';
import { MonthlyStats, Habit, HabitLogs } from '../types';

interface VisualizationPanelProps {
  stats: MonthlyStats;
  habits: Habit[];
  logs: HabitLogs;
  currentDate: Date;
  aiMessage: string | null;
  aiTone: string;
  loadingAI: boolean;
  onRefreshAI: () => void;
}

const CATEGORY_COLORS: Record<string, string> = {
  Health: '#10b981', // emerald
  Growth: '#3b82f6', // blue
  Career: '#8b5cf6', // violet
  Mental: '#f59e0b', // amber
  General: '#64748b', // slate
};

export const VisualizationPanel: React.FC<VisualizationPanelProps> = ({
  stats,
  habits,
  logs,
  currentDate,
  aiMessage,
  aiTone,
  loadingAI,
  onRefreshAI
}) => {
  const getToneColor = () => {
    switch (aiTone) {
      case 'warning': return 'bg-orange-500/10 border-orange-500/30 text-orange-400';
      case 'celebratory': return 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400';
      default: return 'bg-blue-500/10 border-blue-500/30 text-blue-400';
    }
  };

  // 1. Prepare Data for Radar Chart (Life Balance)
  const radarData = useMemo(() => {
    const categories: Record<string, { total: number; completed: number }> = {};

    // Initialize stats per category
    habits.forEach(h => {
      if (!categories[h.category]) categories[h.category] = { total: 0, completed: 0 };
    });

    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const daysPassed = new Date().getDate(); // approximate for current month context

    habits.forEach(h => {
      // Calculate max possible for this habit so far
      categories[h.category].total += daysPassed;

      // Calculate actuals
      for (let d = 1; d <= daysPassed; d++) {
        const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
        if (logs[dateStr]?.includes(h.id)) {
          categories[h.category].completed += 1;
        }
      }
    });

    return Object.keys(categories).map(cat => ({
      subject: cat,
      A: categories[cat].total > 0 
        ? Math.round((categories[cat].completed / categories[cat].total) * 100) 
        : 0,
      fullMark: 100
    }));
  }, [habits, logs, currentDate]);

  // 2. Prepare Data for Stacked Bar Chart (Volume - Last 7 Days)
  const volumeData = useMemo(() => {
    const data = [];
    const today = new Date();

    for (let i = 6; i >= 0; i--) {
      const d = new Date(today);
      d.setDate(today.getDate() - i);
      const dateStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;

      const dayEntry: any = { name: d.toLocaleDateString('en-US', { weekday: 'short' }) };

      // Initialize categories to 0
      Object.keys(CATEGORY_COLORS).forEach(c => dayEntry[c] = 0);

      // Count completions
      const dayLogs = logs[dateStr] || [];
      dayLogs.forEach(habitId => {
        const habit = habits.find(h => h.id === habitId);
        if (habit) {
          const cat = CATEGORY_COLORS[habit.category] ? habit.category : 'General';
          dayEntry[cat] = (dayEntry[cat] || 0) + 1;
        }
      });

      data.push(dayEntry);
    }
    return data;
  }, [logs, habits]);

  return (
    <div className="flex flex-col h-full gap-6 overflow-y-auto pr-2">

      {/* AI Assistant */}
      <div className={`p-6 rounded-3xl border backdrop-blur-sm transition-all duration-500 ${getToneColor()} relative overflow-hidden group shrink-0`}>
        <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
          <Sparkles size={64} />
        </div>
        <div className="flex items-center gap-3 mb-3">
          <h3 className="text-lg font-bold">Daily Insight</h3>
        </div>
        <p className="text-sm font-medium leading-relaxed min-h-[40px]">
          {loadingAI ? <span className="animate-pulse">Analyzing...</span> : aiMessage || "Start tracking to get insights!"}
        </p>
      </div>

      {/* Radar Chart - Life Balance */}
      <div className="bg-surface rounded-3xl border border-slate-700 p-6 flex flex-col min-h-[300px] shrink-0">
        <h3 className="text-slate-300 font-semibold mb-2 flex items-center gap-2">
          <PieIcon size={16} className="text-accent" />
          Life Balance
        </h3>
        <div className="flex-1 w-full h-full min-h-0">
          <ResponsiveContainer width="100%" height="100%">
            <RadarChart cx="50%" cy="50%" outerRadius="70%" data={radarData}>
              <PolarGrid stroke="#334155" />
              <PolarAngleAxis dataKey="subject" tick={{ fill: '#94a3b8', fontSize: 12 }} />
              <PolarRadiusAxis angle={30} domain={[0, 100]} tick={false} axisLine={false} />
              <Radar
                name="Score"
                dataKey="A"
                stroke="#8b5cf6"
                strokeWidth={2}
                fill="#8b5cf6"
                fillOpacity={0.4}
              />
              <Tooltip 
                contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #334155', borderRadius: '8px' }}
                itemStyle={{ color: '#fff' }}
              />
            </RadarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Stacked Bar Chart - Volume */}
      <div className="bg-surface rounded-3xl border border-slate-700 p-6 flex flex-col min-h-[300px] shrink-0">
        <h3 className="text-slate-300 font-semibold mb-4 flex items-center gap-2">
          <Activity size={16} className="text-primary" />
          7-Day Volume
        </h3>
        <div className="flex-1 w-full h-full min-h-0">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={volumeData} margin={{ left: -20, right: 0 }}>
              <XAxis dataKey="name" tick={{ fill: '#64748b', fontSize: 10 }} axisLine={false} tickLine={false} />
              <YAxis tick={{ fill: '#64748b', fontSize: 10 }} axisLine={false} tickLine={false} />
              <Tooltip 
                contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #334155', borderRadius: '8px' }}
                cursor={{ fill: '#334155', opacity: 0.2 }}
              />
              {Object.keys(CATEGORY_COLORS).map((cat) => (
                <Bar key={cat} dataKey={cat} stackId="a" fill={CATEGORY_COLORS[cat]} radius={[0, 0, 0, 0]} />
              ))}
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { 
  LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, ReferenceLine,
  PieChart, Pie, Cell, Label
} from 'recharts';
import { Habit, HabitLogs } from '../types';
import { ArrowLeft, CheckCircle2, TrendingUp } from 'lucide-react';

interface HabitDetailProps {
  habit: Habit;
  logs: HabitLogs;
  currentDate: Date;
  onBack: () => void;
}

export const HabitDetail: React.FC<HabitDetailProps> = ({
  habit,
  logs,
  currentDate,
  onBack
}) => {
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();
  const daysInMonth = new Date(year, month + 1, 0).getDate();

  // 1. Trend Line Data (Cumulative Growth)
  const trendData = useMemo(() => {
    const data = [];
    let cumulative = 0;
    const today = new Date().getDate();
    // Use days passed if current month, else full month
    const isCurrentMonth = new Date().getMonth() === month && new Date().getFullYear() === year;
    const limitDay = isCurrentMonth ? today : daysInMonth;

    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const done = logs[dateStr]?.includes(habit.id);

      if (i <= limitDay) {
        if (done) cumulative += 1;
        data.push({ day: i, actual: cumulative, ideal: i }); // ideal assumes 1/day
      }
    }
    return data;
  }, [habit, logs, year, month, daysInMonth]);

  // 2. Donut Data (Consistency)
  const donutData = useMemo(() => {
    const total = trendData.length; // Days passed
    const completed = trendData[total - 1]?.actual || 0;
    const missed = total - completed;

    return [
      { name: 'Completed', value: completed },
      { name: 'Missed', value: missed }
    ];
  }, [trendData]);

  // 3. Heatmap Data (Calendar Grid)
  const heatmapGrid = useMemo(() => {
    // We want a grid: Rows = Mon-Sun (0-6), Cols = Weeks
    // Let's generate all days and map them to x,y
    const days = [];
    // Start from Day 1
    const firstDayOfWeek = new Date(year, month, 1).getDay(); // 0 = Sun
    // Adjust to Monday start (0=Mon, 6=Sun)
    const startOffset = firstDayOfWeek === 0 ? 6 : firstDayOfWeek - 1;

    for (let i = 1; i <= daysInMonth; i++) {
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const done = logs[dateStr]?.includes(habit.id);

      // Calculate position
      const dayIndex = startOffset + (i - 1);
      const col = Math.floor(dayIndex / 7);
      const row = dayIndex % 7;

      days.push({ day: i, done, col, row });
    }
    return days;
  }, [year, month, daysInMonth, logs, habit]);

  return (
    <div className="flex flex-col h-full gap-6 animate-in slide-in-from-right duration-300">

      {/* Header */}
      <div className="flex items-center gap-4 p-2">
        <button onClick={onBack} className="p-2 hover:bg-slate-700 rounded-full transition-colors">
          <ArrowLeft size={20} />
        </button>
        <div>
          <h2 className="text-2xl font-bold text-white">{habit.name}</h2>
          <span className="text-xs px-2 py-1 rounded bg-slate-700 text-slate-300">{habit.category}</span>
        </div>
      </div>

      {/* Row 1: Donut & Heatmap */}
      <div className="flex gap-6 h-[250px]">
        {/* Donut: Daily Status / Consistency */}
        <div className="flex-1 bg-surface rounded-3xl border border-slate-700 p-4 flex flex-col items-center justify-center relative">
          <h3 className="absolute top-4 left-4 text-sm font-semibold text-slate-400 flex items-center gap-2">
            <CheckCircle2 size={14} /> Consistency
          </h3>
          <div className="w-full h-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={donutData}
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                  stroke="none"
                >
                  <Cell fill="#3b82f6" />
                  <Cell fill="#334155" />
                  <Label 
                    value={`${donutData[0].value}/${donutData[0].value + donutData[1].value}`} 
                    position="center" 
                    className="fill-white text-xl font-bold"
                  />
                </Pie>
              </PieChart>
            </ResponsiveContainer>
          </div>
          <p className="text-xs text-slate-500 mt-[-10px]">Days Completed</p>
        </div>

        {/* Heatmap: Calendar Grid */}
        <div className="flex-[2] bg-surface rounded-3xl border border-slate-700 p-6 relative">
           <h3 className="text-sm font-semibold text-slate-400 mb-4 flex items-center gap-2">
            Calendar Heatmap
          </h3>
          <div className="flex gap-2 h-full items-center justify-center">
            {/* We render columns of weeks */}
            <div className="grid grid-rows-7 gap-1 h-[140px] text-[10px] text-slate-500 mr-2 leading-none py-1">
               <span>Mon</span><span>Tue</span><span>Wed</span><span>Thu</span><span>Fri</span><span>Sat</span><span>Sun</span>
            </div>
            <div className="grid grid-flow-col grid-rows-7 gap-2">
               {heatmapGrid.map((d) => (
                 <div 
                   key={d.day}
                   title={`Day ${d.day}`}
                   className={`w-5 h-5 rounded-sm transition-all hover:scale-125 ${d.done ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.5)]' : 'bg-slate-800'}`}
                   style={{ gridColumn: d.col + 1, gridRow: d.row + 1 }}
                 />
               ))}
            </div>
          </div>
        </div>
      </div>

      {/* Row 2: Trend Line */}
      <div className="flex-1 bg-surface rounded-3xl border border-slate-700 p-6 flex flex-col">
        <h3 className="text-slate-300 font-semibold mb-4 flex items-center gap-2">
          <TrendingUp size={16} className="text-success" />
          Growth Trajectory
        </h3>
        <div className="flex-1 w-full h-full min-h-0">
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={trendData}>
              <XAxis dataKey="day" hide />
              <Tooltip 
                 contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #334155', borderRadius: '8px' }}
                 itemStyle={{ color: '#fff' }}
                 labelFormatter={(val) => `Day ${val}`}
              />
              <ReferenceLine stroke="#94a3b8" strokeDasharray="3 3" segment={[{ x: 1, y: 0 }, { x: trendData.length, y: trendData.length }]} />
              <Line 
                type="monotone" 
                dataKey="actual" 
                stroke="#10b981" 
                strokeWidth={4} 
                dot={{ r: 0 }}
                activeDot={{ r: 6, fill: '#10b981' }}
              />
            </LineChart>
          </ResponsiveContainer>
        </div>
        <p className="text-center text-xs text-slate-500 mt-2">Dashed line represents perfect consistency</p>
      </div>

    </div>
  );
};

import React, { useRef, useEffect } from 'react';
import { Check, X, ChevronRight } from 'lucide-react';
import { Habit, HabitLogs } from '../types';

interface HabitGridProps {
  habits: Habit[];
  logs: HabitLogs;
  currentDate: Date;
  selectedHabitId: string | null;
  onToggle: (habitId: string, dateStr: string) => void;
  onAddHabit: () => void;
  onDeleteHabit: (id: string) => void;
  onSelectHabit: (id: string) => void;
}

export const HabitGrid: React.FC<HabitGridProps> = ({
  habits,
  logs,
  currentDate,
  selectedHabitId,
  onToggle,
  onAddHabit,
  onDeleteHabit,
  onSelectHabit
}) => {
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  // Calculate days in the month
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const daysArray = Array.from({ length: daysInMonth }, (_, i) => i + 1);

  // Auto-scroll to today
  useEffect(() => {
    if (scrollContainerRef.current) {
      const today = new Date().getDate();
      const scrollPos = Math.max(0, (today - 4) * 60);
      scrollContainerRef.current.scrollLeft = scrollPos;
    }
  }, [currentDate]);

  const getDayLabel = (day: number) => {
    const date = new Date(year, month, day);
    return date.toLocaleDateString('en-US', { weekday: 'narrow' });
  };

  const isToday = (day: number) => {
    const today = new Date();
    return (
      day === today.getDate() &&
      month === today.getMonth() &&
      year === today.getFullYear()
    );
  };

  const formatDate = (day: number) => {
    return `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
  };

  return (
    <div className="flex flex-col h-full bg-surface rounded-3xl overflow-hidden shadow-2xl border border-slate-700">
      {/* Header / Controls */}
      <div className="p-6 border-b border-slate-700 flex justify-between items-center bg-slate-900/50">
        <div>
          <h2 className="text-2xl font-bold text-white">Habit Matrix</h2>
          <p className="text-slate-400 text-sm">Select a habit name for details</p>
        </div>
        <button
          onClick={onAddHabit}
          className="px-4 py-2 bg-primary hover:bg-blue-600 text-white rounded-lg transition-colors font-medium flex items-center gap-2"
        >
          <span>+ New Habit</span>
        </button>
      </div>

      {/* Grid Container */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Sticky Left Column: Habit Names */}
        <div className="w-56 flex-shrink-0 bg-surface z-20 border-r border-slate-700 shadow-xl">
          <div className="h-12 border-b border-slate-700 bg-slate-800/80 backdrop-blur sticky top-0 z-30 flex items-center px-4 font-semibold text-slate-300">
            Habit Name
          </div>
          {habits.map((habit) => (
            <div
              key={habit.id}
              className={`h-14 border-b border-slate-700/50 flex items-center justify-between px-4 group transition-all cursor-pointer border-l-4 ${selectedHabitId === habit.id ? 'bg-slate-700/50 border-l-primary' : 'border-l-transparent hover:bg-slate-800'}`}
              onClick={() => onSelectHabit(habit.id)}
            >
              <div className="flex flex-col overflow-hidden">
                <span className={`truncate text-sm font-medium ${selectedHabitId === habit.id ? 'text-white' : 'text-slate-300'}`} title={habit.name}>
                  {habit.name}
                </span>
                <span className="text-[10px] text-slate-500">{habit.category}</span>
              </div>

              <div className="flex items-center gap-2">
                <button 
                  onClick={(e) => { e.stopPropagation(); onDeleteHabit(habit.id); }}
                  className="opacity-0 group-hover:opacity-100 text-slate-500 hover:text-danger transition-opacity p-1"
                >
                  <X size={14} />
                </button>
                <ChevronRight size={14} className={`text-slate-600 ${selectedHabitId === habit.id ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`} />
              </div>
            </div>
          ))}
          {habits.length === 0 && (
            <div className="p-4 text-sm text-slate-500 italic">No habits added yet.</div>
          )}
        </div>

        {/* Scrollable Days Area */}
        <div 
          ref={scrollContainerRef}
          className="flex-1 overflow-x-auto overflow-y-hidden"
        >
          <div className="inline-block min-w-full">
            {/* Days Header */}
            <div className="flex">
              {daysArray.map((day) => (
                <div
                  key={day}
                  className={`w-12 h-12 flex-shrink-0 flex flex-col items-center justify-center border-b border-r border-slate-700/50 ${
                    isToday(day) ? 'bg-primary/20 text-primary' : 'bg-slate-800/50 text-slate-400'
                  }`}
                >
                  <span className="text-[10px] uppercase font-bold">{getDayLabel(day)}</span>
                  <span className={`text-sm font-semibold ${isToday(day) ? 'text-white' : ''}`}>{day}</span>
                </div>
              ))}
            </div>

            {/* Checkboxes Grid */}
            <div>
              {habits.map((habit) => (
                <div key={habit.id} className="flex h-14 border-b border-slate-700/30">
                  {daysArray.map((day) => {
                    const dateStr = formatDate(day);
                    const isCompleted = logs[dateStr]?.includes(habit.id);
                    const today = new Date();
                    const checkDate = new Date(year, month, day);
                    const isFuture = checkDate > today;

                    return (
                      <div
                        key={`${habit.id}-${day}`}
                        className={`w-12 h-full flex-shrink-0 flex items-center justify-center border-r border-slate-700/30 ${
                          isCompleted ? 'bg-primary/5' : ''
                        }`}
                      >
                        <button
                          disabled={isFuture}
                          onClick={() => onToggle(habit.id, dateStr)}
                          className={`
                            w-6 h-6 rounded flex items-center justify-center transition-all duration-200
                            ${
                              isCompleted
                                ? 'bg-primary text-white scale-100 shadow-[0_0_10px_rgba(59,130,246,0.5)]'
                                : 'bg-slate-700 text-transparent scale-75 hover:scale-90 hover:bg-slate-600'
                            }
                            ${isFuture ? 'opacity-20 cursor-not-allowed' : 'cursor-pointer'}
                          `}
                        >
                          <Check size={14} strokeWidth={4} />
                        </button>
                      </div>
                    );
                  })}
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Habit, HabitLogs, MonthlyStats, AppView } from './types';
import { HabitGrid } from './components/HabitGrid';
import { VisualizationPanel } from './components/VisualizationPanel';
import { HabitDetail } from './components/HabitDetail';
import { getProgressInsight, getEndOfMonthReview } from './services/geminiService';
import { ChevronLeft, ChevronRight, FileText, LayoutDashboard, Sparkles } from 'lucide-react';

const DEFAULT_HABITS: Habit[] = [
  { id: '1', name: 'Morning Jog', category: 'Health' },
  { id: '2', name: 'Read 30 mins', category: 'Growth' },
  { id: '3', name: 'Code Project', category: 'Career' },
  { id: '4', name: 'Meditation', category: 'Mental' },
];

function App() {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [habits, setHabits] = useState<Habit[]>(() => {
    const saved = localStorage.getItem('habits');
    return saved ? JSON.parse(saved) : DEFAULT_HABITS;
  });
  const [logs, setLogs] = useState<HabitLogs>(() => {
    const saved = localStorage.getItem('logs');
    return saved ? JSON.parse(saved) : {};
  });

  const [view, setView] = useState<AppView>(AppView.TRACKER);
  const [selectedHabitId, setSelectedHabitId] = useState<string | null>(null);

  const [aiInsight, setAiInsight] = useState<{ message: string; tone: string } | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);
  const [reviewText, setReviewText] = useState<string>("");

  // Persistence
  useEffect(() => {
    localStorage.setItem('habits', JSON.stringify(habits));
    localStorage.setItem('logs', JSON.stringify(logs));
  }, [habits, logs]);

  // Statistics Calculation
  const stats: MonthlyStats = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const today = new Date().getDate();
    // Only count days up to today if looking at current month, else whole month
    const isCurrentMonth = month === new Date().getMonth() && year === new Date().getFullYear();
    const daysPassed = isCurrentMonth ? today : daysInMonth;

    let totalCompleted = 0;
    const totalPossible = habits.length * daysPassed;

    // Calculate Daily Trend
    const dailyTrend = Array.from({ length: daysInMonth }, (_, i) => {
      const day = i + 1;
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
      const completedCount = logs[dateStr]?.length || 0;
      // Only add to total if day has passed
      if (day <= daysPassed) totalCompleted += completedCount;

      return {
        day,
        completed: completedCount,
        total: habits.length
      };
    });

    // Calculate Individual Habit Performance
    const habitPerformance = habits.map(habit => {
      let count = 0;
      for (let d = 1; d <= daysPassed; d++) {
        const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
        if (logs[dateStr]?.includes(habit.id)) count++;
      }
      return {
        id: habit.id,
        name: habit.name,
        count,
        rate: totalPossible > 0 ? (count / daysPassed) * 100 : 0
      };
    });

    return {
      totalPossible,
      totalCompleted,
      completionRate: totalPossible > 0 ? (totalCompleted / totalPossible) * 100 : 0,
      dailyTrend,
      habitPerformance
    };
  }, [logs, habits, currentDate]);

  // AI Trigger
  const fetchInsight = useCallback(async () => {
    setLoadingAI(true);
    const result = await getProgressInsight(stats, currentDate);
    setAiInsight(result);
    setLoadingAI(false);
  }, [stats, currentDate]);

  // Initial AI Fetch
  useEffect(() => {
    // Debounce to avoid too many calls on initial load
    const t = setTimeout(() => {
      if (!aiInsight) fetchInsight();
    }, 1000);
    return () => clearTimeout(t);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); 

  const handleToggleHabit = (habitId: string, dateStr: string) => {
    setLogs(prev => {
      const dayLogs = prev[dateStr] || [];
      const isCompleted = dayLogs.includes(habitId);
      const newDayLogs = isCompleted
        ? dayLogs.filter(id => id !== habitId)
        : [...dayLogs, habitId];

      return { ...prev, [dateStr]: newDayLogs };
    });
  };

  const handleAddHabit = () => {
    const name = prompt("Enter habit name:");
    if (!name) return;

    // Simple category prompt
    const categories = ['Health', 'Growth', 'Career', 'Mental', 'General'];
    const catInput = prompt(`Enter Category (${categories.join(', ')}):`, 'General');
    const category = categories.find(c => c.toLowerCase() === catInput?.toLowerCase()) || 'General';

    setHabits(prev => [...prev, { id: Date.now().toString(), name, category }]);
  };

  const handleDeleteHabit = (id: string) => {
    if (confirm("Delete this habit? History will remain.")) {
      setHabits(prev => prev.filter(h => h.id !== id));
      if (selectedHabitId === id) setSelectedHabitId(null);
    }
  };

  const changeMonth = (offset: number) => {
    setCurrentDate(prev => {
      const newDate = new Date(prev);
      newDate.setMonth(newDate.getMonth() + offset);
      return newDate;
    });
    setAiInsight(null); 
    setReviewText("");
  };

  const handleGenerateReview = async () => {
    setLoadingAI(true);
    const monthName = currentDate.toLocaleString('default', { month: 'long', year: 'numeric' });
    const review = await getEndOfMonthReview(stats, monthName);
    setReviewText(review);
    setLoadingAI(false);
  };

  const selectedHabit = habits.find(h => h.id === selectedHabitId);

  return (
    <div className="min-h-screen bg-background text-slate-200 p-4 md:p-8 flex items-center justify-center font-sans">
      <div className="w-full max-w-[1600px] h-[90vh] flex flex-col gap-6">

        {/* Top Bar: Month Navigation & View Toggle */}
        <div className="flex justify-between items-center bg-surface p-4 rounded-2xl border border-slate-700 shadow-lg">
          <div className="flex items-center gap-4">
            <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-slate-700 rounded-lg transition-colors">
              <ChevronLeft />
            </button>
            <h1 className="text-2xl font-bold w-48 text-center">
              {currentDate.toLocaleString('default', { month: 'long', year: 'numeric' })}
            </h1>
            <button onClick={() => changeMonth(1)} className="p-2 hover:bg-slate-700 rounded-lg transition-colors">
              <ChevronRight />
            </button>
          </div>

          <div className="flex gap-2">
            <button 
              onClick={() => {
                setView(AppView.TRACKER);
                setSelectedHabitId(null);
              }}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${view === AppView.TRACKER ? 'bg-primary text-white shadow-lg shadow-blue-500/30' : 'text-slate-400 hover:text-white'}`}
            >
              <LayoutDashboard size={18} />
              Tracker
            </button>
            <button 
              onClick={() => {
                setView(AppView.REVIEW);
                if (!reviewText) handleGenerateReview();
              }}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${view === AppView.REVIEW ? 'bg-accent text-white shadow-lg shadow-violet-500/30' : 'text-slate-400 hover:text-white'}`}
            >
              <FileText size={18} />
              Monthly Review
            </button>
          </div>
        </div>

        {/* Main Content Area */}
        <div className="flex-1 flex gap-6 min-h-0 overflow-hidden">

          {view === AppView.TRACKER ? (
            <>
              {/* Left Side: 3/5 width */}
              <div className="flex-[3] min-w-0 h-full">
                <HabitGrid 
                  habits={habits}
                  logs={logs}
                  currentDate={currentDate}
                  selectedHabitId={selectedHabitId}
                  onToggle={handleToggleHabit}
                  onAddHabit={handleAddHabit}
                  onDeleteHabit={handleDeleteHabit}
                  onSelectHabit={setSelectedHabitId}
                />
              </div>

              {/* Right Side: 2/5 width - Swaps between Macro and Micro views */}
              <div className="flex-[2] min-w-0 h-full">
                {selectedHabit ? (
                  <HabitDetail 
                    habit={selectedHabit}
                    logs={logs}
                    currentDate={currentDate}
                    onBack={() => setSelectedHabitId(null)}
                  />
                ) : (
                  <VisualizationPanel 
                    stats={stats}
                    habits={habits}
                    logs={logs}
                    currentDate={currentDate}
                    aiMessage={aiInsight?.message || null}
                    aiTone={aiInsight?.tone || 'neutral'}
                    loadingAI={loadingAI}
                    onRefreshAI={fetchInsight}
                  />
                )}
              </div>
            </>
          ) : (
            <div className="w-full bg-surface rounded-3xl border border-slate-700 p-8 overflow-y-auto">
              {/* Review View Content (Existing) */}
              <h2 className="text-3xl font-bold mb-6 text-white flex items-center gap-3">
                <Sparkles className="text-accent" />
                AI Monthly Review
              </h2>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-sm mb-1">Completion Rate</div>
                  <div className="text-4xl font-bold text-primary">{stats.completionRate.toFixed(1)}%</div>
                </div>
                <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-sm mb-1">Top Performer</div>
                  <div className="text-2xl font-bold text-success truncate">
                    {stats.habitPerformance.sort((a,b) => b.rate - a.rate)[0]?.name || '-'}
                  </div>
                </div>
                <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-700">
                  <div className="text-slate-400 text-sm mb-1">Needs Focus</div>
                  <div className="text-2xl font-bold text-danger truncate">
                    {stats.habitPerformance.sort((a,b) => a.rate - b.rate)[0]?.name || '-'}
                  </div>
                </div>
              </div>

              <div className="bg-slate-900/50 p-8 rounded-2xl border border-slate-700">
                {loadingAI ? (
                   <div className="flex items-center gap-3 text-slate-400">
                     <div className="animate-spin h-5 w-5 border-2 border-primary border-t-transparent rounded-full"></div>
                     Generating review...
                   </div>
                ) : (
                  <article className="prose prose-invert max-w-none">
                     <pre className="whitespace-pre-wrap font-sans text-slate-300 text-lg leading-relaxed">{reviewText}</pre>
                  </article>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default App;

