import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Habit, HabitLogs, MonthlyStats } from './types';
import { Sidebar } from './components/Sidebar';
import { HabitGrid } from './components/HabitGrid';
import { VisualizationPanel } from './components/VisualizationPanel';
import { HabitDetail } from './components/HabitDetail';
import { Journal } from './components/Journal';
import { Settings } from './components/Settings';
import { AddHabitModal } from './components/AddHabitModal';
import { ConfirmModal } from './components/ConfirmModal';
import { LoginPage } from './components/LoginPage';
import { getProgressInsight } from './services/geminiService';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { AuthProvider, useAuth } from './context/AuthContext';
import { db } from './firebase';
import { 
  collection, 
  query, 
  onSnapshot, 
  addDoc, 
  deleteDoc, 
  doc, 
  setDoc,
  getDoc
} from 'firebase/firestore';

const AppContent = () => {
  const { currentUser } = useAuth();
  const [currentDate, setCurrentDate] = useState(new Date());

  // Data State from Firestore
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<HabitLogs>({});

  const [view, setView] = useState('DASHBOARD');
  const [selectedHabitId, setSelectedHabitId] = useState<string | null>(null);

  // Modals state
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [habitToDelete, setHabitToDelete] = useState<string | null>(null);

  const [aiInsight, setAiInsight] = useState<{ message: string; tone: string } | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);

  // 1. Fetch Habits from Firestore
  useEffect(() => {
    if (!currentUser) return;

    const q = query(collection(db, 'users', currentUser.uid, 'habits'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedHabits: Habit[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as Habit));
      setHabits(fetchedHabits);
    });

    return () => unsubscribe();
  }, [currentUser]);

  // 2. Fetch Logs from Firestore
  useEffect(() => {
    if (!currentUser) return;

    const q = query(collection(db, 'users', currentUser.uid, 'logs'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedLogs: HabitLogs = {};
      snapshot.docs.forEach(doc => {
        fetchedLogs[doc.id] = doc.data().completed || [];
      });
      setLogs(fetchedLogs);
    });

    return () => unsubscribe();
  }, [currentUser]);

  // Statistics Calculation
  const stats: MonthlyStats = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const today = new Date().getDate();
    const isCurrentMonth = month === new Date().getMonth() && year === new Date().getFullYear();
    const daysPassed = isCurrentMonth ? today : daysInMonth;

    let totalCompleted = 0;
    const totalPossible = habits.length * daysPassed;

    const dailyTrend = Array.from({ length: daysInMonth }, (_, i) => {
      const day = i + 1;
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
      const completedCount = logs[dateStr]?.length || 0;
      if (day <= daysPassed) totalCompleted += completedCount;
      return { day, completed: completedCount, total: habits.length };
    });

    const habitPerformance = habits.map(habit => {
      let count = 0;
      for (let d = 1; d <= daysPassed; d++) {
        const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
        if (logs[dateStr]?.includes(habit.id)) count++;
      }
      return {
        id: habit.id,
        name: habit.name,
        count,
        rate: totalPossible > 0 ? (count / daysPassed) * 100 : 0
      };
    });

    return {
      totalPossible,
      totalCompleted,
      completionRate: totalPossible > 0 ? (totalCompleted / totalPossible) * 100 : 0,
      dailyTrend,
      habitPerformance
    };
  }, [logs, habits, currentDate]);

  // AI Trigger
  const fetchInsight = useCallback(async () => {
    setLoadingAI(true);
    const result = await getProgressInsight(stats, currentDate);
    setAiInsight(result);
    setLoadingAI(false);
  }, [stats, currentDate]);

  useEffect(() => {
    // Only fetch insight if we have some data
    if (habits.length > 0) {
      const t = setTimeout(() => { if (!aiInsight) fetchInsight(); }, 2000);
      return () => clearTimeout(t);
    }
  }, [habits, logs]); 

  // Handlers
  const handleToggleHabit = async (habitId: string, dateStr: string) => {
    if (!currentUser) return;

    const logRef = doc(db, 'users', currentUser.uid, 'logs', dateStr);

    // Optimistic update for UI responsiveness could be done here, 
    // but onSnapshot is usually fast enough.

    try {
      const docSnap = await getDoc(logRef);
      if (docSnap.exists()) {
        const currentCompleted = docSnap.data().completed || [];
        const isCompleted = currentCompleted.includes(habitId);
        let newCompleted;
        if (isCompleted) {
          newCompleted = currentCompleted.filter((id: string) => id !== habitId);
        } else {
          newCompleted = [...currentCompleted, habitId];
        }
        await setDoc(logRef, { completed: newCompleted }, { merge: true });
      } else {
        await setDoc(logRef, { completed: [habitId] });
      }
    } catch (e) {
      console.error("Error toggling habit:", e);
    }
  };

  const handleAddHabit = () => {
    setIsAddModalOpen(true);
  };

  const confirmAddHabit = async (name: string, category: string) => {
    if (!currentUser) return;
    try {
      await addDoc(collection(db, 'users', currentUser.uid, 'habits'), {
        name,
        category,
        createdAt: new Date()
      });
    } catch (e) {
      console.error("Error adding habit:", e);
    }
  };

  const handleDeleteHabit = (id: string) => {
    setHabitToDelete(id);
  };

  const confirmDeleteHabit = async () => {
    if (habitToDelete && currentUser) {
      try {
        await deleteDoc(doc(db, 'users', currentUser.uid, 'habits', habitToDelete));
        if (selectedHabitId === habitToDelete) setSelectedHabitId(null);
        setHabitToDelete(null);
      } catch (e) {
        console.error("Error deleting habit:", e);
      }
    }
  };

  const changeMonth = (offset: number) => {
    setCurrentDate(prev => {
      const newDate = new Date(prev);
      newDate.setMonth(newDate.getMonth() + offset);
      return newDate;
    });
    setAiInsight(null); 
  };

  const selectedHabit = habits.find(h => h.id === selectedHabitId);

  if (!currentUser) {
    return <LoginPage />;
  }

  return (
    <div className="flex h-screen bg-background text-slate-200 overflow-hidden font-sans">

      {/* 1. Sidebar */}
      <Sidebar currentView={view} onNavigate={setView} />

      {/* 2. Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0">

        {/* Header (Date Nav) */}
        <header className="h-16 flex items-center justify-between px-8 border-b border-slate-700 bg-surface/50 backdrop-blur-sm z-40 shrink-0">
           <h1 className="text-xl font-bold text-white tracking-wide">
             {view === 'DASHBOARD' ? 'My Progress' : view === 'JOURNAL' ? 'Journal' : 'Settings'}
           </h1>

           {view === 'DASHBOARD' && (
             <div className="flex items-center gap-4 bg-slate-800/50 rounded-lg p-1">
                <button onClick={() => changeMonth(-1)} className="p-1 hover:bg-slate-700 rounded transition-colors text-slate-400 hover:text-white">
                  <ChevronLeft size={18} />
                </button>
                <span className="text-sm font-semibold w-32 text-center text-white">
                  {currentDate.toLocaleString('default', { month: 'long', year: 'numeric' })}
                </span>
                <button onClick={() => changeMonth(1)} className="p-1 hover:bg-slate-700 rounded transition-colors text-slate-400 hover:text-white">
                  <ChevronRight size={18} />
                </button>
             </div>
           )}
        </header>

        {/* Dynamic Content */}
        <main className="flex-1 overflow-hidden p-6 relative">

          {view === 'DASHBOARD' ? (
            <div className="grid grid-cols-1 lg:grid-cols-10 gap-6 h-full">

              {/* Left Column (70%): Active Zone - Habit List */}
              <div className="lg:col-span-7 h-full min-h-0 flex flex-col">
                <HabitGrid 
                  habits={habits}
                  logs={logs}
                  currentDate={currentDate}
                  selectedHabitId={selectedHabitId}
                  onToggle={handleToggleHabit}
                  onAddHabit={handleAddHabit}
                  onDeleteHabit={handleDeleteHabit}
                  onSelectHabit={setSelectedHabitId}
                />
              </div>

              {/* Right Column (30%): Insight Zone - Analytics Widgets */}
              <div className="lg:col-span-3 h-full min-h-0">
                {selectedHabit ? (
                  <HabitDetail 
                    habit={selectedHabit}
                    logs={logs}
                    currentDate={currentDate}
                    onClose={() => setSelectedHabitId(null)}
                  />
                ) : (
                  <VisualizationPanel 
                    stats={stats}
                    habits={habits}
                    logs={logs}
                    currentDate={currentDate}
                    aiMessage={aiInsight?.message || null}
                    aiTone={aiInsight?.tone || 'neutral'}
                    loadingAI={loadingAI}
                    onRefreshAI={fetchInsight}
                  />
                )}
              </div>

            </div>
          ) : view === 'JOURNAL' ? (
            <Journal habits={habits} logs={logs} />
          ) : (
            <Settings />
          )}

          {/* Modals */}
          <AddHabitModal 
            isOpen={isAddModalOpen} 
            onClose={() => setIsAddModalOpen(false)} 
            onAdd={confirmAddHabit} 
          />

          <ConfirmModal 
            isOpen={!!habitToDelete}
            title="Delete Habit?"
            message="This will permanently remove this habit and all its history. This action cannot be undone."
            onConfirm={confirmDeleteHabit}
            onCancel={() => setHabitToDelete(null)}
          />

        </main>
      </div>
    </div>
  );
};

export default function App() {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
}

import React, { useState, useEffect } from 'react';
import { Save, Calendar, Tag, Sparkles, Trophy } from 'lucide-react';
import { Habit, HabitLogs, JournalEntry } from '../types';
import { useAuth } from '../context/AuthContext';
import { db } from '../firebase';
import { collection, query, orderBy, onSnapshot, addDoc } from 'firebase/firestore';

interface JournalProps {
  habits: Habit[];
  logs: HabitLogs;
}

const MOODS = [
  { label: 'Great', emoji: '😁', color: 'bg-emerald-500/20 text-emerald-400 border-emerald-500/50' },
  { label: 'Good', emoji: '🙂', color: 'bg-blue-500/20 text-blue-400 border-blue-500/50' },
  { label: 'Okay', emoji: '😐', color: 'bg-yellow-500/20 text-yellow-400 border-yellow-500/50' },
  { label: 'Bad', emoji: '🙁', color: 'bg-orange-500/20 text-orange-400 border-orange-500/50' },
  { label: 'Terrible', emoji: '😫', color: 'bg-red-500/20 text-red-400 border-red-500/50' },
];

const TAGS = ['Busy', 'Sick', 'Travel', 'Rest Day', 'Energetic', 'Lazy', 'Focused'];

export const Journal: React.FC<JournalProps> = ({ habits, logs }) => {
  const { currentUser } = useAuth();
  const [entries, setEntries] = useState<JournalEntry[]>([]);

  // Form State
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [mood, setMood] = useState<string>('');
  const [selectedTags, setSelectedTags] = useState<string[]>([]);
  const [content, setContent] = useState('');

  // Fetch Entries from Firestore
  useEffect(() => {
    if (!currentUser) return;

    const q = query(
      collection(db, 'users', currentUser.uid, 'journal'), 
      orderBy('date', 'desc')
    );

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedEntries = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as JournalEntry[];
      setEntries(fetchedEntries);
    });

    return () => unsubscribe();
  }, [currentUser]);

  const toggleTag = (tag: string) => {
    setSelectedTags(prev => 
      prev.includes(tag) ? prev.filter(t => t !== tag) : [...prev, tag]
    );
  };

  const handleSave = async () => {
    if (!mood) {
      alert("Please select a mood!");
      return;
    }
    if (!currentUser) return;

    try {
      await addDoc(collection(db, 'users', currentUser.uid, 'journal'), {
        date,
        mood,
        tags: selectedTags,
        content,
        createdAt: new Date()
      });

      // Reset form partially
      setContent('');
      setMood('');
      setSelectedTags([]);
    } catch (e) {
      console.error("Error saving journal entry:", e);
      alert("Failed to save entry. Please try again.");
    }
  };

  const isPerfectStreak = (dateStr: string) => {
    if (habits.length === 0) return false;
    const completedCount = logs[dateStr]?.length || 0;
    return completedCount === habits.length;
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-full p-2">

      {/* LEFT COLUMN: Input Zone */}
      <div className="lg:col-span-1 bg-surface rounded-3xl border border-slate-700 p-6 flex flex-col gap-6 overflow-y-auto">
        <h2 className="text-xl font-bold text-white flex items-center gap-2">
          <Sparkles className="text-accent" size={20} />
          Daily Reflection
        </h2>

        {/* Date Selector */}
        <div className="flex flex-col gap-2">
          <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Date</label>
          <div className="relative">
            <input 
              type="date" 
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-xl p-3 text-white focus:ring-2 focus:ring-primary outline-none"
            />
          </div>
        </div>

        {/* Mood Selector */}
        <div className="flex flex-col gap-2">
          <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Mood</label>
          <div className="flex justify-between gap-1">
            {MOODS.map((m) => (
              <button
                key={m.label}
                onClick={() => setMood(m.label)}
                className={`flex-1 p-2 rounded-xl border transition-all hover:scale-105 flex flex-col items-center gap-1 ${
                  mood === m.label 
                    ? m.color 
                    : 'bg-slate-800 border-slate-700 text-slate-500 opacity-60 hover:opacity-100'
                }`}
                title={m.label}
              >
                <span className="text-2xl">{m.emoji}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Tag Selector */}
        <div className="flex flex-col gap-2">
          <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Context Tags</label>
          <div className="flex flex-wrap gap-2">
            {TAGS.map(tag => (
              <button
                key={tag}
                onClick={() => toggleTag(tag)}
                className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-colors ${
                  selectedTags.includes(tag)
                    ? 'bg-primary/20 border-primary text-primary'
                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500'
                }`}
              >
                {tag}
              </button>
            ))}
          </div>
        </div>

        {/* Text Area */}
        <div className="flex flex-col gap-2 flex-1 min-h-[150px]">
          <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Highlight of the Day</label>
          <textarea 
            value={content}
            onChange={(e) => setContent(e.target.value)}
            placeholder="What went well today? What was challenging?"
            className="w-full h-full bg-slate-900 border border-slate-700 rounded-xl p-4 text-slate-300 focus:ring-2 focus:ring-primary outline-none resize-none placeholder:text-slate-600 leading-relaxed"
          />
        </div>

        <button 
          onClick={handleSave}
          className="w-full py-3 bg-primary hover:bg-blue-600 text-white font-bold rounded-xl transition-all shadow-lg shadow-blue-500/25 flex items-center justify-center gap-2"
        >
          <Save size={18} />
          Save Entry
        </button>
      </div>

      {/* RIGHT COLUMN: History Feed */}
      <div className="lg:col-span-2 flex flex-col h-full min-h-0">
        <h2 className="text-xl font-bold text-white mb-4 flex items-center gap-2 px-2">
          <Calendar size={20} className="text-slate-400" />
          Journal History
        </h2>

        <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar space-y-4">
          {entries.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-slate-500 italic">
              <span className="text-4xl mb-4">📖</span>
              No entries yet. Start writing your first one!
            </div>
          ) : (
            entries.map((entry) => {
              const moodConfig = MOODS.find(m => m.label === entry.mood);
              const perfect = isPerfectStreak(entry.date);

              return (
                <div key={entry.id} className="bg-surface rounded-2xl border border-slate-700 p-5 hover:border-slate-600 transition-colors group relative overflow-hidden">
                  {/* Perfect Streak Badge */}
                  {perfect && (
                    <div className="absolute top-0 right-0 bg-yellow-500/10 text-yellow-400 px-3 py-1 rounded-bl-xl border-l border-b border-yellow-500/20 flex items-center gap-1.5 text-xs font-bold">
                      <Trophy size={12} />
                      Perfect Day
                    </div>
                  )}

                  {/* Header */}
                  <div className="flex items-center gap-3 mb-3">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center text-xl bg-slate-800 border border-slate-700 ${moodConfig?.color.replace('bg-', 'bg-opacity-10 ')}`}>
                      {moodConfig?.emoji}
                    </div>
                    <div>
                      <h3 className="text-white font-semibold">
                        {new Date(entry.date).toLocaleDateString(undefined, { weekday: 'long', month: 'short', day: 'numeric' })}
                      </h3>
                      <div className="flex gap-2 text-xs text-slate-500">
                        {entry.mood}
                      </div>
                    </div>
                  </div>

                  {/* Content */}
                  <p className="text-slate-300 leading-relaxed mb-4 text-sm whitespace-pre-wrap">
                    {entry.content || <span className="italic text-slate-600">No details added.</span>}
                  </p>

                  {/* Footer Tags */}
                  {entry.tags.length > 0 && (
                    <div className="flex flex-wrap gap-2 pt-3 border-t border-slate-700/50">
                      {entry.tags.map(tag => (
                        <span key={tag} className="text-[10px] font-medium px-2 py-0.5 rounded bg-slate-800 text-slate-400 border border-slate-700 flex items-center gap-1">
                          <Tag size={10} /> {tag}
                        </span>
                      ))}
                    </div>
                  )}
                </div>
              );
            })
          )}
        </div>
      </div>

    </div>
  );
};

