import React, { createContext, useContext, useEffect, useState } from 'react';
import { Habit, HabitLogs, JournalEntry } from '../types';

interface LocalContextType {
  userName: string;
  habits: Habit[];
  logs: HabitLogs;
  journalEntries: JournalEntry[];
  setUserName: (name: string) => void;
  addHabit: (name: string, category: string) => void;
  deleteHabit: (id: string) => void;
  toggleHabit: (habitId: string, dateStr: string) => void;
  addJournalEntry: (mood: string, tags: string[], content: string, date: string) => void;
  deleteJournalEntry: (id: string) => void;
  clearData: () => void;
  getSyncCode: () => string;
  importSyncCode: (code: string) => boolean;
}

const LocalContext = createContext<LocalContextType | undefined>(undefined);

export const useLocalContext = () => {
  const context = useContext(LocalContext);
  if (!context) {
    throw new Error('useLocalContext must be used within a LocalProvider');
  }
  return context;
};

const STORAGE_KEY = 'habitpulse_data_v1';

export const LocalProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  // Initial State Load
  const loadState = () => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        return JSON.parse(saved);
      }
    } catch (e) {
      console.error("Failed to load data", e);
    }
    return {
      userName: '',
      habits: [],
      logs: {},
      journalEntries: []
    };
  };

  const [data, setData] = useState(loadState());

  // Save on Change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  }, [data]);

  const setUserName = (name: string) => {
    setData(prev => ({ ...prev, userName: name }));
  };

  const addHabit = (name: string, category: string) => {
    const newHabit: Habit = {
      id: crypto.randomUUID(),
      name,
      category
    };
    setData(prev => ({ ...prev, habits: [...prev.habits, newHabit] }));
  };

  const deleteHabit = (id: string) => {
    setData(prev => ({
      ...prev,
      habits: prev.habits.filter(h => h.id !== id),
      // Optional: Clean up logs for this habit if desired, keeping simple for now
    }));
  };

  const toggleHabit = (habitId: string, dateStr: string) => {
    setData(prev => {
      const currentDayLogs = prev.logs[dateStr] || [];
      const isCompleted = currentDayLogs.includes(habitId);

      let newDayLogs;
      if (isCompleted) {
        newDayLogs = currentDayLogs.filter(id => id !== habitId);
      } else {
        newDayLogs = [...currentDayLogs, habitId];
      }

      return {
        ...prev,
        logs: {
          ...prev.logs,
          [dateStr]: newDayLogs
        }
      };
    });
  };

  const addJournalEntry = (mood: string, tags: string[], content: string, date: string) => {
    const newEntry: JournalEntry = {
      id: crypto.randomUUID(),
      date, // Using YYYY-MM-DD
      mood: mood as any,
      tags,
      content
    };
    setData(prev => ({
      ...prev,
      journalEntries: [newEntry, ...prev.journalEntries]
    }));
  };

  const deleteJournalEntry = (id: string) => {
    setData(prev => ({
      ...prev,
      journalEntries: prev.journalEntries.filter(e => e.id !== id)
    }));
  };

  const clearData = () => {
    if(window.confirm("Are you sure you want to reset all data?")) {
        localStorage.removeItem(STORAGE_KEY);
        setData({ userName: '', habits: [], logs: {}, journalEntries: [] });
    }
  };

  const getSyncCode = () => {
    const syncData = {
      userName: data.userName,
      habits: data.habits,
      logs: data.logs,
      journalEntries: data.journalEntries,
      timestamp: new Date().toISOString()
    };
    try {
      // Use encodeURIComponent + unescape to handle UTF-8 characters (emojis) correctly in btoa
      const jsonString = JSON.stringify(syncData);
      return btoa(unescape(encodeURIComponent(jsonString)));
    } catch (e) {
      console.error("Failed to generate sync code", e);
      return "";
    }
  };

  const importSyncCode = (code: string) => {
    try {
      // Decode: atob -> escape -> decodeURIComponent handles UTF-8 correctly
      const jsonString = decodeURIComponent(escape(atob(code)));
      const parsed = JSON.parse(jsonString);

      // Basic validation
      if (!parsed.habits || !parsed.journalEntries || typeof parsed.userName !== 'string') {
        return false;
      }

      const newData = {
          userName: parsed.userName,
          habits: parsed.habits || [],
          logs: parsed.logs || {},
          journalEntries: parsed.journalEntries || []
      };

      setData(newData); // React state update
      // We also strictly force local storage update here to ensure persistence before reload
      localStorage.setItem(STORAGE_KEY, JSON.stringify(newData));
      return true;
    } catch (e) {
      console.error("Failed to import", e);
      return false;
    }
  };

  const value = {
    userName: data.userName,
    habits: data.habits,
    logs: data.logs,
    journalEntries: data.journalEntries,
    setUserName,
    addHabit,
    deleteHabit,
    toggleHabit,
    addJournalEntry,
    deleteJournalEntry,
    clearData,
    getSyncCode,
    importSyncCode
  };

  return (
    <LocalContext.Provider value={value}>
      {children}
    </LocalContext.Provider>
  );
};

import React, { useState } from 'react';
import { useLocalContext } from '../context/LocalContext';
import { Copy, Download, Upload, CheckCircle, AlertCircle } from 'lucide-react';

export const SyncSettings = () => {
  const { getSyncCode, importSyncCode } = useLocalContext();
  const [importText, setImportText] = useState('');
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const handleCopy = async () => {
    const code = getSyncCode();
    try {
      await navigator.clipboard.writeText(code);
      alert('Magic Sync Code copied to clipboard! Paste this on your other device.');
    } catch (err) {
      console.error("Failed to copy:", err);
      alert("Failed to copy code. Please try again.");
    }
  };

  const handleImport = () => {
    if (!importText.trim()) return;

    // Safety check handled by UI context, but good to double check intent
    if(!window.confirm("This will overwrite your current data with the data from the code. Are you sure?")) {
      return;
    }

    const success = importSyncCode(importText.trim());
    if (success) {
      setStatus('success');
      alert('Data Restored Successfully!');
      window.location.reload();
    } else {
      setStatus('error');
      alert('Invalid Sync Code. Please check the code and try again.');
    }
  };

  return (
    <div className="h-full bg-surface rounded-2xl border border-slate-700 p-8 overflow-y-auto custom-scrollbar flex flex-col items-center">

      <div className="text-center mb-8 max-w-lg">
        <h2 className="text-3xl font-bold text-white mb-2 flex items-center justify-center gap-3">
          <span className="text-2xl">⚙️</span> Settings & Sync
        </h2>
        <p className="text-slate-400">Manage your data, backup your progress, or sync between devices using Magic Codes.</p>
      </div>

      <div className="max-w-2xl w-full space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">

        {/* Export Section */}
