import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { MonthlyStats } from './types';
import { Sidebar } from './components/Sidebar';
import { HabitGrid } from './components/HabitGrid';
import { VisualizationPanel } from './components/VisualizationPanel';
import { HabitDetail } from './components/HabitDetail';
import { Journal } from './components/Journal';
import { SyncSettings } from './components/SyncSettings';
import { AddHabitModal } from './components/AddHabitModal';
import { ConfirmModal } from './components/ConfirmModal';
import { WelcomeScreen } from './components/WelcomeScreen';
import { getProgressInsight } from './services/geminiService';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { LocalProvider, useLocalContext } from './context/LocalContext';

const AppContent = () => {
  const { userName, habits, logs, addHabit, deleteHabit } = useLocalContext();
  const [currentDate, setCurrentDate] = useState(new Date());

  const [view, setView] = useState('DASHBOARD');
  const [selectedHabitId, setSelectedHabitId] = useState<string | null>(null);

  // Modals state
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [habitToDelete, setHabitToDelete] = useState<string | null>(null);

  const [aiInsight, setAiInsight] = useState<{ message: string; tone: string } | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);

  // Statistics Calculation
  const stats: MonthlyStats = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const today = new Date().getDate();
    const isCurrentMonth = month === new Date().getMonth() && year === new Date().getFullYear();
    const daysPassed = isCurrentMonth ? today : daysInMonth;

    let totalCompleted = 0;
    const totalPossible = habits.length * daysPassed;

    const dailyTrend = Array.from({ length: daysInMonth }, (_, i) => {
      const day = i + 1;
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
      const completedCount = logs[dateStr]?.length || 0;
      if (day <= daysPassed) totalCompleted += completedCount;
      return { day, completed: completedCount, total: habits.length };
    });

    const habitPerformance = habits.map(habit => {
      let count = 0;
      for (let d = 1; d <= daysPassed; d++) {
        const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
        if (logs[dateStr]?.includes(habit.id)) count++;
      }
      return {
        id: habit.id,
        name: habit.name,
        count,
        rate: totalPossible > 0 ? (count / daysPassed) * 100 : 0
      };
    });

    return {
      totalPossible,
      totalCompleted,
      completionRate: totalPossible > 0 ? (totalCompleted / totalPossible) * 100 : 0,
      dailyTrend,
      habitPerformance
    };
  }, [logs, habits, currentDate]);

  // AI Trigger
  const fetchInsight = useCallback(async () => {
    setLoadingAI(true);
    const result = await getProgressInsight(stats, currentDate);
    setAiInsight(result);
    setLoadingAI(false);
  }, [stats, currentDate]);

  useEffect(() => {
    // Only fetch insight if we have some data
    if (habits.length > 0) {
      const t = setTimeout(() => { if (!aiInsight) fetchInsight(); }, 2000);
      return () => clearTimeout(t);
    }
  }, [habits, logs]); 

  const changeMonth = (offset: number) => {
    setCurrentDate(prev => {
      const newDate = new Date(prev);
      newDate.setMonth(newDate.getMonth() + offset);
      return newDate;
    });
    setAiInsight(null); 
  };

  const handleConfirmDeleteHabit = () => {
    if (habitToDelete) {
      deleteHabit(habitToDelete);
      if (selectedHabitId === habitToDelete) {
        setSelectedHabitId(null);
      }
      setHabitToDelete(null);
    }
  };

  const selectedHabit = habits.find(h => h.id === selectedHabitId);

  // Flow Control
  if (!userName) {
    return <WelcomeScreen />;
  }

  return (
    <div className="flex h-screen bg-background text-slate-200 overflow-hidden font-sans">

      {/* 1. Sidebar */}
      <Sidebar currentView={view} onNavigate={setView} />

      {/* 2. Main Content Area */}
      <div className="flex-1 flex flex-col min-w-0">

        {/* Header (Date Nav) */}
        <header className="h-16 flex items-center justify-between px-8 border-b border-slate-700 bg-surface/50 backdrop-blur-sm z-40 shrink-0">
           <h1 className="text-xl font-bold text-white tracking-wide">
             {view === 'DASHBOARD' ? `Welcome, ${userName}` : view === 'JOURNAL' ? 'Journal' : 'Settings'}
           </h1>

           {view === 'DASHBOARD' && (
             <div className="flex items-center gap-4 bg-slate-800/50 rounded-lg p-1">
                <button onClick={() => changeMonth(-1)} className="p-1 hover:bg-slate-700 rounded transition-colors text-slate-400 hover:text-white">
                  <ChevronLeft size={18} />
                </button>
                <span className="text-sm font-semibold w-32 text-center text-white">
                  {currentDate.toLocaleString('default', { month: 'long', year: 'numeric' })}
                </span>
                <button onClick={() => changeMonth(1)} className="p-1 hover:bg-slate-700 rounded transition-colors text-slate-400 hover:text-white">
                  <ChevronRight size={18} />
                </button>
             </div>
           )}
        </header>

        {/* Dynamic Content */}
        <main className="flex-1 overflow-hidden p-6 relative">

          {view === 'DASHBOARD' ? (
            <div className="grid grid-cols-1 lg:grid-cols-10 gap-6 h-full">

              {/* Left Column (70%): Active Zone - Habit List */}
              <div className="lg:col-span-7 h-full min-h-0 flex flex-col">
                <HabitGrid 
                  currentDate={currentDate}
                  selectedHabitId={selectedHabitId}
                  onAddHabit={() => setIsAddModalOpen(true)}
                  onSelectHabit={setSelectedHabitId}
                  onDeleteHabit={(id) => setHabitToDelete(id)}
                />
              </div>

              {/* Right Column (30%): Insight Zone - Analytics Widgets */}
              <div className="lg:col-span-3 h-full min-h-0">
                {selectedHabit ? (
                  <HabitDetail 
                    habit={selectedHabit}
                    logs={logs}
                    currentDate={currentDate}
                    onClose={() => setSelectedHabitId(null)}
                  />
                ) : (
                  <VisualizationPanel 
                    stats={stats}
                    habits={habits}
                    logs={logs}
                    currentDate={currentDate}
                    aiMessage={aiInsight?.message || null}
                    aiTone={aiInsight?.tone || 'neutral'}
                    loadingAI={loadingAI}
                    onRefreshAI={fetchInsight}
                  />
                )}
              </div>

            </div>
          ) : view === 'JOURNAL' ? (
            <Journal />
          ) : (
            <SyncSettings />
          )}

          {/* Modals */}
          <AddHabitModal 
            isOpen={isAddModalOpen} 
            onClose={() => setIsAddModalOpen(false)} 
            onAdd={addHabit} 
          />

          <ConfirmModal 
            isOpen={!!habitToDelete}
            title="Delete Habit?"
            message="This will permanently remove this habit and all its history. This action cannot be undone."
            onConfirm={handleConfirmDeleteHabit}
            onCancel={() => setHabitToDelete(null)}
          />

        </main>
      </div>
    </div>
  );
};

export default function App() {
  return (
    <LocalProvider>
      <AppContent />
    </LocalProvider>
  );
}

import React, { createContext, useContext, useEffect, useState } from 'react';
import { Habit, HabitLogs, JournalEntry } from '../types';

interface LocalContextType {
  userName: string;
  habits: Habit[];
  logs: HabitLogs;
  journalEntries: JournalEntry[];
  setUserName: (name: string) => void;
  addHabit: (name: string, category: string) => void;
  deleteHabit: (id: string) => void;
  toggleHabit: (habitId: string, dateStr: string) => void;
  addJournalEntry: (mood: string, tags: string[], content: string, date: string) => void;
  deleteJournalEntry: (id: string) => void;
  clearData: () => void;
  getSyncCode: () => string;
  importSyncCode: (code: string) => boolean;
}

const LocalContext = createContext<LocalContextType | undefined>(undefined);

export const useLocalContext = () => {
  const context = useContext(LocalContext);
  if (!context) {
    throw new Error('useLocalContext must be used within a LocalProvider');
  }
  return context;
};

const STORAGE_KEY = 'habitpulse_data_v1';

export const LocalProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  // Initial State Load
  const loadState = () => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        return JSON.parse(saved);
      }
    } catch (e) {
      console.error("Failed to load data", e);
    }
    return {
      userName: '',
      habits: [],
      logs: {},
      journalEntries: []
    };
  };

  const [data, setData] = useState(loadState());

  // Save on Change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  }, [data]);

  const setUserName = (name: string) => {
    setData(prev => ({ ...prev, userName: name }));
  };

  const addHabit = (name: string, category: string) => {
    const newHabit: Habit = {
      id: crypto.randomUUID(),
      name,
      category
    };
    setData(prev => ({ ...prev, habits: [...prev.habits, newHabit] }));
  };

  const deleteHabit = (id: string) => {
    setData(prev => ({
      ...prev,
      habits: prev.habits.filter(h => h.id !== id),
      // Optional: Clean up logs for this habit if desired, keeping simple for now
    }));
  };

  const toggleHabit = (habitId: string, dateStr: string) => {
    setData(prev => {
      const currentDayLogs = prev.logs[dateStr] || [];
      const isCompleted = currentDayLogs.includes(habitId);

      let newDayLogs;
      if (isCompleted) {
        newDayLogs = currentDayLogs.filter(id => id !== habitId);
      } else {
        newDayLogs = [...currentDayLogs, habitId];
      }

      return {
        ...prev,
        logs: {
          ...prev.logs,
          [dateStr]: newDayLogs
        }
      };
    });
  };

  const addJournalEntry = (mood: string, tags: string[], content: string, date: string) => {
    const newEntry: JournalEntry = {
      id: crypto.randomUUID(),
      date, // Using YYYY-MM-DD
      mood: mood as any,
      tags,
      content
    };
    setData(prev => ({
      ...prev,
      journalEntries: [newEntry, ...prev.journalEntries]
    }));
  };

  const deleteJournalEntry = (id: string) => {
    setData(prev => ({
      ...prev,
      journalEntries: prev.journalEntries.filter(e => e.id !== id)
    }));
  };

  const clearData = () => {
    if(window.confirm("Are you sure you want to reset all data?")) {
        localStorage.removeItem(STORAGE_KEY);
        setData({ userName: '', habits: [], logs: {}, journalEntries: [] });
    }
  };

  const getSyncCode = () => {
    const syncData = {
      userName: data.userName,
      habits: data.habits,
      logs: data.logs,
      journalEntries: data.journalEntries,
      timestamp: new Date().toISOString()
    };
    try {
      // Use TextEncoder to handle UTF-8 characters (emojis) correctly
      const jsonString = JSON.stringify(syncData);
      const bytes = new TextEncoder().encode(jsonString);
      // Convert Uint8Array to binary string
      const binString = Array.from(bytes, (byte) => String.fromCharCode(byte)).join("");
      return btoa(binString);
    } catch (e) {
      console.error("Failed to generate sync code", e);
      return "";
    }
  };

  const importSyncCode = (code: string) => {
    try {
      // Remove any whitespaces/newlines from copy-paste
      const cleanCode = code.replace(/\s/g, '');

      // Decode Base64 to binary string
      const binString = atob(cleanCode);

      // Convert binary string to Uint8Array
      const bytes = Uint8Array.from(binString, (m) => m.codePointAt(0)!);

      // Decode UTF-8 bytes to JSON string
      const jsonString = new TextDecoder().decode(bytes);

      const parsed = JSON.parse(jsonString);

      // Validation: Ensure it's an object
      if (!parsed || typeof parsed !== 'object') {
        console.error("Import failed: Parsed data is not an object");
        return false;
      }

      // Reconstruct state with fallbacks for safety
      const newData = {
          userName: typeof parsed.userName === 'string' ? parsed.userName : (data.userName || ''),
          habits: Array.isArray(parsed.habits) ? parsed.habits : [],
          logs: parsed.logs && typeof parsed.logs === 'object' ? parsed.logs : {},
          journalEntries: Array.isArray(parsed.journalEntries) ? parsed.journalEntries : []
      };

      setData(newData);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(newData));
      return true;
    } catch (e) {
      console.error("Failed to import sync code:", e);
      return false;
    }
  };

  const value = {
    userName: data.userName,
    habits: data.habits,
    logs: data.logs,
    journalEntries: data.journalEntries,
    setUserName,
    addHabit,
    deleteHabit,
    toggleHabit,
    addJournalEntry,
    deleteJournalEntry,
    clearData,
    getSyncCode,
    importSyncCode
  };

  return (
    <LocalContext.Provider value={value}>
      {children}
    </LocalContext.Provider>
  );
};

import { GoogleGenAI } from "@google/genai";
import { Habit, JournalEntry } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API_KEY not found in environment variables");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const getAiInsights = async (
  habits: Habit[],
  journalEntries: JournalEntry[]
): Promise<string> => {
  const client = getClient();
  if (!client) {
    throw new Error("API Key invalid or missing");
  }

  // Format data for prompt
  const habitList = habits.map(h => h.name).join(", ") || "No habits tracked yet.";

  // Get last 5 entries to avoid token limits and focus on recent context
  const recentJournals = journalEntries
    .slice(0, 5)
    .map(j => `Date: ${j.date}, Mood: ${j.mood}, Content: ${j.content}`)
    .join("\n") || "No journal entries yet.";

  const prompt = `
    Analyze this user's habit data:
    Habits: ${habitList}

    Recent Journal Entries:
    ${recentJournals}

    Give 3 short, punchy bullet points of advice and 1 motivating sentence. 
    Use emojis. Keep it under 100 words.
  `;

  try {
    const response = await client.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
    });

    return response.text || "Keep pushing forward! You're doing great.";
  } catch (error) {
    console.error("Error generating insights:", error);
    throw new Error("Failed to generate insights");
  }
};

import React, { useState } from 'react';
import { Sparkles, Loader2, AlertCircle } from 'lucide-react';
import { useLocalContext } from '../context/LocalContext';
import { getAiInsights } from '../services/gemini';

export const AiInsights: React.FC = () => {
  const { habits, journalEntries } = useLocalContext();
  const [insight, setInsight] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    setLoading(true);
    setError(null);
    setInsight(null);

    try {
      const result = await getAiInsights(habits, journalEntries);
      setInsight(result);
    } catch (err) {
      console.error(err);
      setError("Check your API Key or try again later.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-surface rounded-2xl border border-slate-700 p-6 shadow-lg mb-6">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-xl font-bold text-white flex items-center gap-2">
          <Sparkles className="text-accent" size={20} />
          AI Coach
        </h2>
      </div>

      {!insight && !loading && !error && (
        <div className="text-center py-6">
          <p className="text-slate-400 mb-4 text-sm">
            Get personalized advice based on your habits and journal entries.
          </p>
          <button
            onClick={handleGenerate}
            className="px-6 py-3 bg-gradient-to-r from-primary to-accent hover:from-blue-600 hover:to-violet-600 text-white font-bold rounded-xl transition-all shadow-lg shadow-violet-500/20 flex items-center gap-2 mx-auto"
          >
            <Sparkles size={18} />
            Generate Insights
          </button>
        </div>
      )}

      {loading && (
        <div className="flex flex-col items-center justify-center py-8 text-slate-400">
          <Loader2 className="animate-spin mb-3 text-primary" size={32} />
          <p className="text-sm animate-pulse">Analyzing your progress...</p>
        </div>
      )}

      {error && (
        <div className="bg-red-500/10 border border-red-500/50 rounded-xl p-4 flex items-center gap-3 text-red-200">
          <AlertCircle size={20} />
          <div className="flex flex-col items-start">
             <span className="text-sm font-bold">Error</span>
             <span className="text-xs">{error}</span>
          </div>
        </div>
      )}

      {insight && (
        <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
          <div className="bg-slate-900/50 rounded-xl p-5 border border-slate-700/50">
            <p className="text-slate-200 whitespace-pre-line leading-relaxed text-sm">
              {insight}
            </p>
          </div>
          <button
            onClick={handleGenerate}
            className="mt-4 text-xs text-slate-500 hover:text-primary transition-colors flex items-center gap-1 mx-auto"
          >
            <Sparkles size={12} /> Refresh Advice
          </button>
        </div>
      )}
    </div>
  );
};
